var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"지금 놀리시는 거죠? 전 살면서 요정을 한 번도 본 적 없는걸요.","JPN":"私のこと、からかってるんですか？　私は人生で一度も妖精なんて見たことありません。","ENG":"You're just messing with me, right? I've never seen a fairy in my life.","TWN":"你在開玩笑吧？我這輩子從沒見過精靈。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"네가 살아남은 이유에 대해, 나는 두 가지 가능성을 생각했어.","JPN":"アナタが生き残った理由について、アタシは二つの可能性を考えたの。","ENG":"I have thought of two possibilities for how you are still alive.","TWN":"關於你能活下來的原因，我想到了二種可能性。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하나는 네가 악마에게 영혼을 바친 대가로 죽지 않은 것.","JPN":"一つはアナタが悪魔に魂を捧げた対価として死を免れたという説。","ENG":"One is that you offered your soul to the devil in return for immortality.","TWN":"一是你把靈魂獻給了魔鬼，所以沒死。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그리고 또 다른 하나는, 네가 살아있길 바라는 <color=#ffd34c>가능성의 존재</color>가 있다는 것.","JPN":"そしてもう一つは、アナタの生存を願う<color=#ffd34c>可能性の存在</color>がいるという説。","ENG":"The other is that there is an <color=#ffd34c>entity of possibilities</color> that wishes you to live.","TWN":"另一種是，有某個希望你活著的<color=#ffd34c>可能性</color>存在。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"만약 전자가 확실했다면… 난 굳이 널 살려두지 않았을 거야.","JPN":"もし前者だったとしたら……アタシはアナタを生かしておかなかったはずよ。","ENG":"If I was certain of the former... I would not have kept you alive.","TWN":"如果是前者…我就不會留你活到現在。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"으윽…","JPN":"ううっ……","ENG":"Ngh...","TWN":"嗯嗯…"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하지만 네가 지금까지 보여준 행보는 영혼 없는 인간과는 달랐어.","JPN":"でも、今までアナタが見せてくれた言動は魂のない人間とは違っていたわ。","ENG":"However, the actions you have shown are far from those of a soulless person.","TWN":"你至今的表現不像是失去靈魂的手下。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"오히려, 우릴 도우러 온 구원자에 가까웠지.","JPN":"むしろ、アタシたちを助けにきた救世主のようだった。","ENG":"As a matter of fact, you are closer to a savior who has come to help us.","TWN":"反而更像是來幫助我們的救贖者。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"구원자…","JPN":"救世主……","ENG":"A savior…","TWN":"救贖者…"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"요정님이 꿈에서 나에게 말씀하셨단다.","JPN":"妖精さんが夢に出てきてお話ししてくれたの。","ENG":"A fairy came into my dreams and said this to me.","TWN":"精靈在夢中悄悄對我說。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"우리와 다르게… 너에겐 빛이 있다고 했어.","JPN":"普通の人とは違い……あなたには光があるって。","ENG":"\\"Unlike me... there is light within you.","TWN":"你和我們不同…你有光。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"아무리 절망적인 상황에서도… 모든 걸 이겨낼 빛이.","JPN":"どんなに絶望的な状況になっても……すべてに打ち勝てる光が。","ENG":"No matter how tough it gets... your light will overcome it all.\\"","TWN":"無論多麼絕望的情況…都能克服的光。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"제가 살아있는 게, 제가 지금껏 찾지 못한 요정 덕분일지도 모른다니.","JPN":"私が生きているのが、今まで見つけられなかった妖精のおかげかもしれないなんて。","ENG":"You think that I'm alive because of a fairy that I haven't been able to find?","TWN":"我能活下來，可能是因為我沒找到的那個精靈？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"만약 그게 사실이라면… 요정이 저에게 뭘 남겨준 거죠?","JPN":"もしそれが本当なら……妖精は私に何を残してくれたのでしょう？","ENG":"If that's true... then what did this fairy leave me with?","TWN":"如果這是真的…那精靈給我留下了什麼？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"글쎄.","JPN":"さあね。","ENG":"Who knows?","TWN":"不清楚。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 기적의 형태는 네가 가진 무기일 수도, 다른 것일 수도 있어.","JPN":"その奇跡の形はアナタが持っている武器か、それとも別の何かかもしれないわ。","ENG":"A miracle may take form as your weapon, or perhaps something else.","TWN":"那奇蹟的形態可能是你手中的武器，也可能是其他東西。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그게 뭔지 아는 존재가 있다면, 오직 너와 그 요정뿐일 거야.","JPN":"それが何なのか知っているとしたら、それはアナタとその妖精だけでしょう。","ENG":"If anyone knows of its existence, it will be you and the fairy.","TWN":"知道那是什麼的，只有你和那個精靈。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하지만, 그게 무엇인지 모른다고 해서 조급할 필요는 없어.","JPN":"でも、それがわからないからといって焦る必要はないの。","ENG":"Yet, there is no need to be impatient about not knowing what it is.","TWN":"不過，不知道也不用著急。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"기적이라는 건 언제나처럼 그 자리에 있다가, 어둠 속에서 불현듯 빛나는 법이거든.","JPN":"奇跡というのはいつもそこにあって、闇の中で突然光るものよ。","ENG":"Miracles are always in place, but suddenly shine bright in times of darkness.","TWN":"奇蹟總是存在的，它會在黑暗中突然閃耀。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"정말 이래도 괜찮나요…? 많이 바쁘시다고 들었는데.","JPN":"本当にいいんですか……？　とても忙しいって聞きましたけど。","ENG":"Are you sure about this...? I heard you were extremely busy.","TWN":"這樣真的沒關係嗎…？聽說你很忙。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"사양할 것 없어.","JPN":"遠慮することないわ。","ENG":"No need to decline my offer.","TWN":"不用客氣。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"같이 술을 못 마시니까, 한 번쯤 제대로 된 식사라도 대접해주고 싶었거든.","JPN":"一緒にお酒は飲めないから、一度くらいちゃんとおごってあげたかったの。","ENG":"Since we cannot drink together, I wanted to at least treat you to a proper meal.","TWN":"因為不能一起喝酒，所以至少想請你吃頓像樣的飯。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"으…","JPN":"うう……","ENG":"Err...","TWN":"呃…"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"죄송해요. 제가 술을 못 마셔서…","JPN":"すみません。私、ゲコで……","ENG":"I'm sorry that I can't drink...","TWN":"非常抱歉…"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"일일이 사과할 필요없어.","JPN":"そんなことで謝らないで。","ENG":"No need to apologize for everything.","TWN":"沒必要什麼都道歉。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};